/* Offline local jsPDF-compatible fallback for this app. */
(function () {
  "use strict";
  if (window.jspdf && window.jspdf.jsPDF) return;

  const MM_TO_PT = 72 / 25.4;
  const PAGE_SIZES = { a4: { portrait: [210, 297], landscape: [297, 210] } };

  function asciiText(value) {
    return String(value ?? "")
      .replace(/Å/g, "A").replace(/Ä/g, "A").replace(/Ö/g, "O")
      .replace(/å/g, "a").replace(/ä/g, "a").replace(/ö/g, "o")
      .replace(/[–—]/g, "-").replace(/°/g, " deg")
      .replace(/[^\x20-\x7E]/g, "?");
  }

  function escText(value) {
    return asciiText(value)
      .replace(/\\/g, "\\\\")
      .replace(/\(/g, "\\(")
      .replace(/\)/g, "\\)")
      .replace(/[\r\n]+/g, " ");
  }

  function rgb(args, fallback) {
    const a = Array.isArray(args[0]) ? args[0] : args;
    return [0, 1, 2].map((i) => {
      const v = Number(a[i]);
      return Number.isFinite(v) ? Math.max(0, Math.min(255, v)) : fallback[i];
    });
  }

  function colorOp(prefix, c) {
    return `${(c[0] / 255).toFixed(4)} ${(c[1] / 255).toFixed(4)} ${(c[2] / 255).toFixed(4)} ${prefix}`;
  }

  class MiniJsPDF {
    constructor(opts = {}) {
      this.unit = opts.unit || "mm";
      this.orientation = opts.orientation || "portrait";
      this.format = String(opts.format || "a4").toLowerCase();
      const size = PAGE_SIZES[this.format]?.[this.orientation] || PAGE_SIZES.a4.landscape;
      this.pageW = size[0];
      this.pageH = size[1];
      this.scaleFactor = this.unit === "pt" ? 1 : MM_TO_PT;
      this.ops = [];
      this.fontSize = 10;
      this.fontStyle = "normal";
      this.drawColor = [0, 0, 0];
      this.fillColor = [0, 0, 0];
      this.textColor = [0, 0, 0];
      this.lineWidth = 0.2;
      this.internal = { pageSize: { getWidth: () => this.pageW, getHeight: () => this.pageH } };
    }

    _x(x) { return (Number(x) || 0) * this.scaleFactor; }
    _y(y) { return (this.pageH - (Number(y) || 0)) * this.scaleFactor; }
    _n(v) { return (Number(v) || 0).toFixed(3).replace(/\.000$/, ""); }
    _push(s) { this.ops.push(s); }

    setFont(_name, style = "normal") { this.fontStyle = style || "normal"; return this; }
    setFontSize(size) { this.fontSize = Number(size) || this.fontSize; return this; }
    setTextColor(...args) { this.textColor = rgb(args, this.textColor); return this; }
    setDrawColor(...args) { this.drawColor = rgb(args, this.drawColor); return this; }
    setFillColor(...args) { this.fillColor = rgb(args, this.fillColor); return this; }
    setLineWidth(w) { this.lineWidth = Number(w); if (!Number.isFinite(this.lineWidth)) this.lineWidth = 0.2; return this; }
    setLineDash() { return this; }

    getTextWidth(text) { return asciiText(text).length * this.fontSize * 0.42 / this.scaleFactor; }

    line(x1, y1, x2, y2) {
      this._push(`q ${colorOp("RG", this.drawColor)} ${this._n(this.lineWidth * this.scaleFactor)} w ${this._n(this._x(x1))} ${this._n(this._y(y1))} m ${this._n(this._x(x2))} ${this._n(this._y(y2))} l S Q`);
      return this;
    }

    rect(x, y, w, h, style = "S") {
      const op = String(style).toUpperCase().includes("F") ? "B" : "S";
      this._push(`q ${colorOp("RG", this.drawColor)} ${colorOp("rg", this.fillColor)} ${this._n(this.lineWidth * this.scaleFactor)} w ${this._n(this._x(x))} ${this._n(this._y(y + h))} ${this._n(w * this.scaleFactor)} ${this._n(h * this.scaleFactor)} re ${op} Q`);
      return this;
    }

    circle(x, y, r, style = "S") {
      const cx = this._x(x), cy = this._y(y), rr = Math.max(0, (Number(r) || 0) * this.scaleFactor);
      const c = 0.5522847498 * rr;
      const op = String(style).toUpperCase().includes("F") ? "f" : "S";
      this._push(`q ${colorOp("RG", this.drawColor)} ${colorOp("rg", this.fillColor)} ${this._n(this.lineWidth * this.scaleFactor)} w ${this._n(cx + rr)} ${this._n(cy)} m ${this._n(cx + rr)} ${this._n(cy + c)} ${this._n(cx + c)} ${this._n(cy + rr)} ${this._n(cx)} ${this._n(cy + rr)} c ${this._n(cx - c)} ${this._n(cy + rr)} ${this._n(cx - rr)} ${this._n(cy + c)} ${this._n(cx - rr)} ${this._n(cy)} c ${this._n(cx - rr)} ${this._n(cy - c)} ${this._n(cx - c)} ${this._n(cy - rr)} ${this._n(cx)} ${this._n(cy - rr)} c ${this._n(cx + c)} ${this._n(cy - rr)} ${this._n(cx + rr)} ${this._n(cy - c)} ${this._n(cx + rr)} ${this._n(cy)} c ${op} Q`);
      return this;
    }

    triangle(x1, y1, x2, y2, x3, y3, style = "S") {
      const op = String(style).toUpperCase().includes("F") ? "f" : "S";
      this._push(`q ${colorOp("RG", this.drawColor)} ${colorOp("rg", this.fillColor)} ${this._n(this.lineWidth * this.scaleFactor)} w ${this._n(this._x(x1))} ${this._n(this._y(y1))} m ${this._n(this._x(x2))} ${this._n(this._y(y2))} l ${this._n(this._x(x3))} ${this._n(this._y(y3))} l h ${op} Q`);
      return this;
    }

    text(text, x, y, opts = {}) {
      const angle = Number(opts.angle) || 0;
      const rad = angle * Math.PI / 180;
      const cos = Math.cos(rad).toFixed(6);
      const sin = Math.sin(rad).toFixed(6);
      let tx = this._x(x);
      const ty = this._y(y);
      if (opts.align === "center") tx -= this.getTextWidth(text) * this.scaleFactor / 2;
      if (opts.align === "right") tx -= this.getTextWidth(text) * this.scaleFactor;
      const fontName = this.fontStyle === "bold" ? "F2" : "F1";
      this._push(`q ${colorOp("rg", this.textColor)} BT /${fontName} ${this._n(this.fontSize)} Tf ${cos} ${sin} ${(-sin).toFixed(6)} ${cos} ${this._n(tx)} ${this._n(ty)} Tm (${escText(text)}) Tj ET Q`);
      return this;
    }

    _buildPdf() {
      const pageWpt = this.pageW * this.scaleFactor;
      const pageHpt = this.pageH * this.scaleFactor;
      const stream = this.ops.join("\n");
      const objects = [null];
      const add = (s) => { objects.push(s); return objects.length - 1; };
      const font1Id = add("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>");
      const font2Id = add("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>");
      const contentId = add(`<< /Length ${stream.length} >>\nstream\n${stream}\nendstream`);
      const pagesId = objects.length;
      objects.push(null);
      const pageId = add(`<< /Type /Page /Parent ${pagesId} 0 R /MediaBox [0 0 ${this._n(pageWpt)} ${this._n(pageHpt)}] /Resources << /Font << /F1 ${font1Id} 0 R /F2 ${font2Id} 0 R >> >> /Contents ${contentId} 0 R >>`);
      objects[pagesId] = `<< /Type /Pages /Kids [${pageId} 0 R] /Count 1 >>`;
      const catalogId = add(`<< /Type /Catalog /Pages ${pagesId} 0 R >>`);
      let pdf = "%PDF-1.4\n%offline\n";
      const offsets = [0];
      for (let i = 1; i < objects.length; i++) {
        offsets[i] = pdf.length;
        pdf += `${i} 0 obj\n${objects[i]}\nendobj\n`;
      }
      const xref = pdf.length;
      pdf += `xref\n0 ${objects.length}\n0000000000 65535 f \n`;
      for (let i = 1; i < objects.length; i++) pdf += `${String(offsets[i]).padStart(10, "0")} 00000 n \n`;
      pdf += `trailer\n<< /Size ${objects.length} /Root ${catalogId} 0 R >>\nstartxref\n${xref}\n%%EOF`;
      return pdf;
    }

    save(filename = "ritning.pdf") {
      const pdf = this._buildPdf();
      const blob = new Blob([pdf], { type: "application/pdf" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = filename;
      a.rel = "noopener";
      document.body.appendChild(a);
      a.click();
      a.remove();
      setTimeout(() => URL.revokeObjectURL(url), 2000);
    }
  }

  window.jspdf = { jsPDF: MiniJsPDF };
  window.jsPDF = MiniJsPDF;
})();
